const amqp = require('amqplib');

async function main() {
  try {
    const connection = await amqp.connect('amqp://localhost');
    const channel = await connection.createChannel();

    // Declare queue and exchange
    await channel.assertQueue('', { exclusive: true });
    await channel.assertExchange('payment_exchange', 'direct', { durable: false });

    // Bind queue to exchange
    await channel.bindQueue(channel.queue.name, 'payment_exchange', '', '', null);

    console.log("Waiting for messages in RabbitMQ...");

    // Consume messages from the queue
    channel.consume(channel.queue.name, (msg) => {
      if (msg !== null) {
        const paymentEvent = JSON.parse(msg.content.toString());
        processPayment(paymentEvent);
        channel.ack(msg);
      }
    });
  } catch (err) {
    console.error(err);
  }
}

